import { useRef, useEffect } from 'react';
import { RACE_PREFIXES } from '@wc3-ui/core';
import type { Race } from '@wc3-ui/core';

interface Props {
  race: Race;
  leftOnly?: boolean;
}

type TileIndex = 1 | 2 | 3 | 4;

const TILE_INDICES: readonly TileIndex[] = [1, 2, 3, 4];
const TOP_SLICE_V0 = 0;
const TOP_SLICE_V1 = 0.125;
const TILE2_LEFT_U0 = 0;
const TILE2_LEFT_U1 = 0.33984375;
const TILE2_RIGHT_U0 = 0.79296875;
const TILE2_RIGHT_U1 = 1;

const LEFT_TILE1_WIDTH_VW = 32;
const LEFT_TILE2_WIDTH_VW = 10.875;
const RIGHT_TILE2_WIDTH_VW = 6.875;
const RIGHT_TILE3_WIDTH_VW = 32;
const RIGHT_TILE4_WIDTH_VW = 4;
const SEAM_PX = 1;

function topTilePath(race: Race, index: TileIndex): string {
  const tile = RACE_PREFIXES[race].tile;
  return `/console/${race}/${tile}UITile0${index}.png`;
}

function compileShader(gl: WebGLRenderingContext, type: number, src: string): WebGLShader | null {
  const shader = gl.createShader(type);
  if (!shader) return null;
  gl.shaderSource(shader, src);
  gl.compileShader(shader);
  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    console.error('Top HUD shader compile failed:', gl.getShaderInfoLog(shader));
    gl.deleteShader(shader);
    return null;
  }
  return shader;
}

function createProgram(gl: WebGLRenderingContext): WebGLProgram | null {
  const vertexSource = `
    attribute vec2 a_position;
    attribute vec2 a_uv;
    varying vec2 v_uv;
    void main() {
      gl_Position = vec4(a_position, 0.0, 1.0);
      v_uv = a_uv;
    }
  `;
  const fragmentSource = `
    precision mediump float;
    varying vec2 v_uv;
    uniform sampler2D u_texture;
    void main() {
      vec4 color = texture2D(u_texture, v_uv);
      if (color.a < 0.5) {
        discard;
      }
      gl_FragColor = color;
    }
  `;

  const vertexShader = compileShader(gl, gl.VERTEX_SHADER, vertexSource);
  const fragmentShader = compileShader(gl, gl.FRAGMENT_SHADER, fragmentSource);
  if (!vertexShader || !fragmentShader) return null;

  const program = gl.createProgram();
  if (!program) return null;

  gl.attachShader(program, vertexShader);
  gl.attachShader(program, fragmentShader);
  gl.linkProgram(program);

  gl.deleteShader(vertexShader);
  gl.deleteShader(fragmentShader);

  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    console.error('Top HUD program link failed:', gl.getProgramInfoLog(program));
    gl.deleteProgram(program);
    return null;
  }

  return program;
}

export default function TopHudWebGL({ race, leftOnly }: Props) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // All mutable GL state lives in refs so effects/callbacks always see current values.
  const glRef = useRef<WebGLRenderingContext | null>(null);
  const programRef = useRef<WebGLProgram | null>(null);
  const quadBufferRef = useRef<WebGLBuffer | null>(null);
  const positionLocRef = useRef(-1);
  const uvLocRef = useRef(-1);
  const textureLocRef = useRef<WebGLUniformLocation | null>(null);
  const destroyedRef = useRef(false);
  const drawQueuedRef = useRef(false);
  const drawRafRef = useRef(0);
  const resizeObserverRef = useRef<ResizeObserver | null>(null);
  const textureCacheRef = useRef(new Map<string, WebGLTexture>());
  const textureLoadCacheRef = useRef(new Map<string, Promise<WebGLTexture | null>>());
  const activeTexturesRef = useRef<Record<TileIndex, WebGLTexture> | null>(null);

  // Keep latest props in refs for use inside callbacks without stale closures.
  const raceRef = useRef(race);
  raceRef.current = race;
  const leftOnlyRef = useRef(leftOnly);
  leftOnlyRef.current = leftOnly;

  useEffect(() => {
    const canvas = canvasRef.current!;
    const gl = canvas.getContext('webgl', {
      alpha: true,
      premultipliedAlpha: false,
      antialias: false,
      depth: false,
      stencil: false,
    });

    if (!gl) {
      console.error('WebGL is unavailable for top HUD rendering.');
      return;
    }

    glRef.current = gl;
    const prog = createProgram(gl);
    if (!prog) return;
    programRef.current = prog;

    positionLocRef.current = gl.getAttribLocation(prog, 'a_position');
    uvLocRef.current = gl.getAttribLocation(prog, 'a_uv');
    textureLocRef.current = gl.getUniformLocation(prog, 'u_texture');
    quadBufferRef.current = gl.createBuffer();

    if (positionLocRef.current < 0 || uvLocRef.current < 0 || !textureLocRef.current || !quadBufferRef.current) {
      console.error('Failed to initialize top HUD WebGL buffers.');
      return;
    }

    gl.disable(gl.DEPTH_TEST);
    gl.disable(gl.CULL_FACE);
    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
    gl.clearColor(0, 0, 0, 0);

    void loadRaceTextures(raceRef.current);
    requestDraw();

    const onResize = () => requestDraw();
    window.addEventListener('resize', onResize);

    if (typeof ResizeObserver !== 'undefined') {
      resizeObserverRef.current = new ResizeObserver(() => requestDraw());
      resizeObserverRef.current.observe(canvas);
    }

    return () => {
      destroyedRef.current = true;
      window.removeEventListener('resize', onResize);
      if (resizeObserverRef.current) {
        resizeObserverRef.current.disconnect();
        resizeObserverRef.current = null;
      }
      if (drawRafRef.current) {
        window.cancelAnimationFrame(drawRafRef.current);
      }
      for (const texture of textureCacheRef.current.values()) {
        gl.deleteTexture(texture);
      }
      if (quadBufferRef.current) gl.deleteBuffer(quadBufferRef.current);
      if (programRef.current) gl.deleteProgram(programRef.current);
    };
  }, []);

  useEffect(() => {
    if (!glRef.current || destroyedRef.current) return;
    void loadRaceTextures(race);
  }, [race]);

  useEffect(() => {
    requestDraw();
  }, [leftOnly]);

  const requestDraw = () => {
    if (drawQueuedRef.current || destroyedRef.current) return;
    drawQueuedRef.current = true;
    drawRafRef.current = window.requestAnimationFrame(() => {
      drawQueuedRef.current = false;
      draw();
    });
  };

  const syncCanvasSize = () => {
    const canvas = canvasRef.current;
    const gl = glRef.current;
    if (!gl || !canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const cssWidth = Math.max(1, canvas.clientWidth || 1);
    const cssHeight = Math.max(1, canvas.clientHeight || 1);
    const width = Math.round(cssWidth * dpr);
    const height = Math.round(cssHeight * dpr);
    if (canvas.width !== width || canvas.height !== height) {
      canvas.width = width;
      canvas.height = height;
    }
    gl.viewport(0, 0, width, height);
  };

  const drawQuad = (
    texture: WebGLTexture,
    x: number, y: number, w: number, h: number,
    u0: number, v0: number, u1: number, v1: number,
  ) => {
    const canvas = canvasRef.current;
    const gl = glRef.current;
    const quadBuffer = quadBufferRef.current;
    if (!gl || !quadBuffer || !canvas) return;
    const canvasW = canvas.width;
    const canvasH = canvas.height;
    if (canvasW <= 0 || canvasH <= 0 || w <= 0 || h <= 0) return;

    const x0 = (x / canvasW) * 2 - 1;
    const y0 = 1 - (y / canvasH) * 2;
    const x1 = ((x + w) / canvasW) * 2 - 1;
    const y1 = 1 - ((y + h) / canvasH) * 2;

    const vertices = new Float32Array([
      x0, y0, u0, v0,
      x1, y0, u1, v0,
      x0, y1, u0, v1,
      x1, y0, u1, v0,
      x1, y1, u1, v1,
      x0, y1, u0, v1,
    ]);

    gl.bindTexture(gl.TEXTURE_2D, texture);
    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, vertices, gl.STREAM_DRAW);
    gl.drawArrays(gl.TRIANGLES, 0, 6);
  };

  const draw = () => {
    const canvas = canvasRef.current;
    const gl = glRef.current;
    const program = programRef.current;
    const quadBuffer = quadBufferRef.current;
    const activeTextures = activeTexturesRef.current;
    if (!gl || !program || !quadBuffer || !activeTextures || !canvas) return;

    syncCanvasSize();
    const canvasW = canvas.width;
    const canvasH = canvas.height;
    if (canvasW <= 0 || canvasH <= 0) return;

    gl.clear(gl.COLOR_BUFFER_BIT);
    gl.useProgram(program);
    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuffer);
    gl.enableVertexAttribArray(positionLocRef.current);
    gl.vertexAttribPointer(positionLocRef.current, 2, gl.FLOAT, false, 16, 0);
    gl.enableVertexAttribArray(uvLocRef.current);
    gl.vertexAttribPointer(uvLocRef.current, 2, gl.FLOAT, false, 16, 8);
    gl.activeTexture(gl.TEXTURE0);
    gl.uniform1i(textureLocRef.current, 0);

    const dpr = window.devicePixelRatio || 1;
    const seamPx = SEAM_PX * dpr;
    const vw = canvasW / 100;
    const topHudH = canvasH;

    if (leftOnlyRef.current) {
      const leftSpanVw = LEFT_TILE1_WIDTH_VW + LEFT_TILE2_WIDTH_VW;
      const leftTile1W = (LEFT_TILE1_WIDTH_VW / leftSpanVw) * canvasW + seamPx;
      const leftTile2X = leftTile1W - seamPx;
      const leftTile2W = canvasW - leftTile2X;

      drawQuad(activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
      drawQuad(activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);
      return;
    }

    const leftTile1W = LEFT_TILE1_WIDTH_VW * vw + seamPx;
    const leftTile2W = LEFT_TILE2_WIDTH_VW * vw + seamPx;
    const leftTile2X = leftTile1W - seamPx;

    drawQuad(activeTextures[1], 0, 0, leftTile1W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
    drawQuad(activeTextures[2], leftTile2X, 0, leftTile2W, topHudH, TILE2_LEFT_U0, TOP_SLICE_V0, TILE2_LEFT_U1, TOP_SLICE_V1);

    const rightTile2W = RIGHT_TILE2_WIDTH_VW * vw + seamPx;
    const rightTile3W = RIGHT_TILE3_WIDTH_VW * vw + seamPx;
    const rightTile4W = RIGHT_TILE4_WIDTH_VW * vw + seamPx;
    const rightTile4X = canvasW - rightTile4W;
    const rightTile3X = rightTile4X - (rightTile3W - seamPx);
    const rightTile2X = rightTile3X - (rightTile2W - seamPx);

    drawQuad(activeTextures[2], rightTile2X, 0, rightTile2W, topHudH, TILE2_RIGHT_U0, TOP_SLICE_V0, TILE2_RIGHT_U1, TOP_SLICE_V1);
    drawQuad(activeTextures[3], rightTile3X, 0, rightTile3W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
    drawQuad(activeTextures[4], rightTile4X, 0, rightTile4W, topHudH, 0, TOP_SLICE_V0, 1, TOP_SLICE_V1);
  };

  const loadTexture = (path: string): Promise<WebGLTexture | null> => {
    const gl = glRef.current;
    if (!gl) return Promise.resolve(null);
    const cached = textureCacheRef.current.get(path);
    if (cached) return Promise.resolve(cached);
    const inflight = textureLoadCacheRef.current.get(path);
    if (inflight) return inflight;

    const promise = new Promise<WebGLTexture | null>((resolve) => {
      const image = new Image();
      image.onload = () => {
        const gl = glRef.current;
        if (!gl || destroyedRef.current) {
          textureLoadCacheRef.current.delete(path);
          resolve(null);
          return;
        }
        const texture = gl.createTexture();
        if (!texture) {
          textureLoadCacheRef.current.delete(path);
          resolve(null);
          return;
        }
        gl.bindTexture(gl.TEXTURE_2D, texture);
        gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, image);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
        textureCacheRef.current.set(path, texture);
        textureLoadCacheRef.current.delete(path);
        resolve(texture);
      };
      image.onerror = () => {
        console.error(`Failed to load top HUD texture: ${path}`);
        textureLoadCacheRef.current.delete(path);
        resolve(null);
      };
      image.src = path;
    });

    textureLoadCacheRef.current.set(path, promise);
    return promise;
  };

  const loadRaceTextures = async (race: Race) => {
    if (!glRef.current || destroyedRef.current) return;
    const paths = TILE_INDICES.map((index) => topTilePath(race, index));
    const loaded = await Promise.all(paths.map((path) => loadTexture(path)));
    if (destroyedRef.current || loaded.some((tex) => tex === null)) return;

    activeTexturesRef.current = {
      1: loaded[0]!,
      2: loaded[1]!,
      3: loaded[2]!,
      4: loaded[3]!,
    };
    requestDraw();
  };

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      style={{
        position: 'absolute',
        inset: '0',
        width: '100%',
        height: '100%',
        display: 'block',
        pointerEvents: 'none',
      }}
    />
  );
}

