      cameraNearRef.current = Math.max(8, radius * 0.08);
      cameraFarRef.current = Math.max(cameraNearRef.current + 300, radius * 11.5);
    } else {
      vec3.set(cameraPos.current, 48, -420, 180);
      vec3.set(cameraTarget.current, 0, 0, 100);
      cameraFovRef.current = 0.78;
      cameraNearRef.current = 8;
      cameraFarRef.current = 2200;
    }

