    modelRendererRef.current.setCamera(cameraPos.current, cameraQuat.current);
    modelRendererRef.current.setLightPosition(cameraPos.current);
    modelRendererRef.current.setLightColor(vec3.fromValues(1, 1, 1));
    modelRendererRef.current.setSequence(sequenceIndexRef.current);
