     4→interface WC3RendererContextValue {
     5→  renderer: Renderer;
     6→}
     7→
     8→const WC3RendererContext = createContext<WC3RendererContextValue | null>(null);
     9→
    10→export interface WC3RendererProviderProps {
    11→  children: ReactNode;
    12→  /** Initial race to load textures for. Defaults to 'Human'. */
    13→  race?: Race;
    14→  /** CSS class for the overlay canvas */
    15→  canvasClassName?: string;
    16→}
    17→
    18→export function WC3RendererProvider({ children, race = 'Human', canvasClassName }: WC3RendererProviderProps) {
    19→  const canvasRef = useRef<HTMLCanvasElement>(null);
    20→
    21→  // Create renderer once, synchronously, so children's registration effects
    22→  // fire against the same instance that the canvas init effect will use.
    23→  const rendererRef = useRef<Renderer | null>(null);
    24→  if (rendererRef.current === null) {
    25→    rendererRef.current = new Renderer();
    26→  }
    27→  const renderer = rendererRef.current;
    28→
    29→  useEffect(() => {
    30→    const canvas = canvasRef.current;
    31→    if (!canvas) return;
    32→
    33→    renderer.init(canvas);
    34→    renderer.loadRace(race);
    35→    renderer.preloadAll();
    36→    renderer.start();
    37→
    38→    return () => {
    39→      renderer.destroy();
    40→    };
    41→    // race intentionally excluded: a separate effect handles race changes below
    42→    // eslint-disable-next-line react-hooks/exhaustive-deps
    43→  }, []);
    44→
    45→  useEffect(() => {
    46→    renderer.loadRace(race);
    47→  }, [renderer, race]);
    48→
    49→  return (
    50→    <WC3RendererContext.Provider value={{ renderer }}>
    51→      <canvas
    52→        ref={canvasRef}
    53→        className={canvasClassName}
    54→        style={{
    55→          position: 'fixed',
    56→          inset: 0,
    57→          width: '100%',
    58→          height: '100%',
    59→          pointerEvents: 'none',
    60→          zIndex: 0,
    61→        }}
    62→      />
    63→      {children}
    64→    </WC3RendererContext.Provider>
    65→  );
    66→}
    67→
    68→export function useWC3Renderer(): Renderer {
    69→  const ctx = useContext(WC3RendererContext);
    70→  if (!ctx) {
    71→    throw new Error('useWC3Renderer must be used inside <WC3RendererProvider>');
    72→  }
    73→  return ctx.renderer;
    74→}
