// Resource counter utilities — framework-agnostic.
// State lives in App.tsx as useState; these are pure helper functions.

export function stepCounter(current: number, target: number): number {
  if (current === target) return current;
  const diff = target - current;
  const next = current + Math.sign(diff) * Math.max(1, Math.floor(Math.abs(diff) * 0.2));
  return Math.abs(target - next) < 2 ? target : next;
}

export function nextGoldTarget(prev: number): number {
  return Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 20) - 5));
}

export function nextLumberTarget(prev: number): number {
  return Math.max(0, Math.min(9999, prev + Math.floor(Math.random() * 15) - 4));
}

// Cheat code detection — framework-agnostic.
let cheatBuffer = '';
const CHEATS: Record<string, (gold: number, lumber: number) => { gold: number; lumber: number }> = {
  greedisgood: (gold, lumber) => ({
    gold: Math.min(9999, gold + 500),
    lumber: Math.min(9999, lumber + 500),
  }),
  keysersoze: (gold, lumber) => ({ gold: Math.min(9999, gold + 500), lumber }),
  leafittome: (gold, lumber) => ({ gold, lumber: Math.min(9999, lumber + 500) }),
};

export function handleCheatKey(
  key: string,
  gold: number,
  lumber: number,
  setGoldTarget: (v: number) => void,
  setLumberTarget: (v: number) => void,
) {
  if (key.length === 1 && /[a-z]/i.test(key)) {
    cheatBuffer += key.toLowerCase();
    if (cheatBuffer.length > 20) cheatBuffer = cheatBuffer.slice(-20);
    for (const [code, fn] of Object.entries(CHEATS)) {
      if (cheatBuffer.endsWith(code)) {
        const next = fn(gold, lumber);
        setGoldTarget(next.gold);
        setLumberTarget(next.lumber);
        cheatBuffer = '';
        break;
      }
    }
  }
}

