import { useState, useEffect, useRef } from 'react';

// Custom hook for animated bar percentages
export function useAnimatedBars() {
  const [healthPct, setHealthPct] = useState(75);
  const [manaPct, setManaPct] = useState(60);
  const [xpPct, setXpPct] = useState(40);
  const [buildPct, setBuildPct] = useState(55);

  function animateBars() {
    setHealthPct(Math.floor(Math.random() * 60 + 20));
    setManaPct(Math.floor(Math.random() * 60 + 20));
    setXpPct(Math.floor(Math.random() * 60 + 20));
    setBuildPct(Math.floor(Math.random() * 60 + 20));
  }

  return { healthPct, manaPct, xpPct, buildPct, setHealthPct, setManaPct, setXpPct, setBuildPct, animateBars };
}

// Custom hook for loading bar animation
export function useLoadingBar() {
  const [progress, setProgress] = useState(0);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  function start() {
    setProgress(0);
    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(() => {
      setProgress(prev => {
        const next = prev + Math.random() * 8 + 2;
        if (next >= 100) {
          clearInterval(intervalRef.current!);
          intervalRef.current = null;
          setTimeout(() => {
            setProgress(0);
            setTimeout(() => start(), 100);
          }, 1500);
          return 100;
        }
        return next;
      });
    }, 400);
  }

  function stop() {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }

  useEffect(() => {
    return () => stop();
  }, []);

  return { progress, start, stop };
}

