import { useRef, useState, type ReactNode } from 'react';
import { useRendererRegistration } from '@wc3-ui/react';

interface Props {
  bgPath: string;
  borderPath: string;
  bgDownPath?: string;
  borderDownPath?: string;
  hoverPath?: string;
  disabled?: boolean;
  children?: ReactNode;
}

export default function GlueButton({
  bgPath, borderPath, bgDownPath, borderDownPath, hoverPath, disabled = false, children,
}: Props) {
  const ref = useRef<HTMLButtonElement>(null);
  const [hovered, setHovered] = useState(false);
  const [pressed, setPressed] = useState(false);

  const hoveredRef = useRef(hovered);
  hoveredRef.current = hovered;
  const pressedRef = useRef(pressed);
  pressedRef.current = pressed;

  useRendererRegistration('glueButtons', () => ({
    ref: () => ref.current!,
    hovered: () => hoveredRef.current,
    pressed: () => pressedRef.current,
    disabled,
    bgPath,
    borderPath,
    bgDownPath,
    borderDownPath,
    hoverPath,
  }));

  return (
    <button
      ref={ref}
      className={`wc3-glue-btn${disabled ? ' disabled' : ''}`}
      disabled={disabled}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => { setHovered(false); setPressed(false); }}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
    >
      {children}
    </button>
  );
}

