import { useState, useEffect, useRef } from 'react';
import { parseMDX } from 'war3-model';

const components = [
  { name: 'GoldButton', size: 1.2 },
  { name: 'ResourceCounter', size: 0.8 },
  { name: 'CommandCard', size: 1.9 },
  { name: 'Tooltip', size: 1.4 },
  { name: 'PortraitFrame', size: 1.1 },
  { name: 'HealthBar', size: 0.6 },
  { name: 'Minimap', size: 2.1 },
  { name: 'Dialog', size: 1.7 },
  { name: 'ChatBubble', size: 0.9 },
  { name: 'HeroCard', size: 2.4 },
] as const;

const maxSize = Math.max(...components.map((c) => c.size));
const imageCache = new Map<string, Promise<HTMLImageElement>>();
const buildProgressBarModelPath = '/models/build-progress/BuildProgressBar.mdx';
const fallbackCapRatio = 4 / 128;
let buildProgressBarUvPromise: Promise<{ minU: number; maxU: number }> | null = null;

interface Props {
  buildFillUrl: string;
  buildBorderUrl: string;
}

interface BuildProgressRowBarProps {
  valuePct: number;
  fillUrl: string;
  borderUrl: string;
}

function normalizeTexturePath(path: string): string {
  return path.replace(/\\/g, '/').toLowerCase();
}

async function loadBuildProgressBarUvDomain(): Promise<{ minU: number; maxU: number }> {
  if (buildProgressBarUvPromise) return buildProgressBarUvPromise;

  buildProgressBarUvPromise = (async () => {
    const fallback = { minU: 0, maxU: 1 };
    try {
      const res = await fetch(buildProgressBarModelPath);
      if (!res.ok) return fallback;
      const ab = await res.arrayBuffer();
      const model: any = parseMDX(ab);
      const textures: Array<{ Image?: string }> = model.Textures || [];
      const borderTexIndex = textures.findIndex((tex) =>
        normalizeTexturePath(String(tex?.Image || '')).endsWith('/human-buildprogressbar-border2.blp'),
      );
      if (borderTexIndex < 0) return fallback;

      const materials: Array<{ Layers?: Array<{ TextureID?: number }> }> = model.Materials || [];
      const borderMaterialIndex = materials.findIndex((material) =>
        (material?.Layers || []).some((layer) => layer?.TextureID === borderTexIndex),
      );
      if (borderMaterialIndex < 0) return fallback;

      const geosets: Array<{ MaterialID?: number; TVertices?: number[][] }> = model.Geosets || [];
      const borderGeoset = geosets.find((geoset) => geoset.MaterialID === borderMaterialIndex);
      const uv = borderGeoset?.TVertices?.[0];
      if (!uv || uv.length < 2) return fallback;

      let minU = Infinity;
      let maxU = -Infinity;
      for (let i = 0; i < uv.length; i += 2) {
        const u = uv[i];
        if (u < minU) minU = u;
        if (u > maxU) maxU = u;
      }
      if (!Number.isFinite(minU) || !Number.isFinite(maxU) || maxU <= minU) return fallback;
      return { minU, maxU };
    } catch (err) {
      console.warn('Failed to load BuildProgressBar UV domain, falling back to texture-domain caps.', err);
      return fallback;
    }
  })();

  return buildProgressBarUvPromise;
}

async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
  const cached = imageCache.get(url);
  if (cached) return cached;
  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    img.src = url;
  });
  imageCache.set(url, promise);
  return promise;
}

function deriveBuildBarCapRatio(
  borderImg: HTMLImageElement,
  uvDomain: { minU: number; maxU: number },
): number {
  const width = borderImg.width;
  const height = borderImg.height;
  if (width <= 2 || height <= 0) return fallbackCapRatio;

  const scratch = document.createElement('canvas');
  scratch.width = width;
  scratch.height = height;
  const scratchCtx = scratch.getContext('2d', { willReadFrequently: true });
  if (!scratchCtx) return fallbackCapRatio;

  scratchCtx.clearRect(0, 0, width, height);
  scratchCtx.drawImage(borderImg, 0, 0);
  const data = scratchCtx.getImageData(0, 0, width, height).data;
  const row = Math.floor(height / 2);

  const alphaAt = (x: number) => data[(row * width + x) * 4 + 3];
  let firstOpaque = 0;
  while (firstOpaque < width && alphaAt(firstOpaque) === 0) firstOpaque += 1;

  let firstGap = firstOpaque;
  while (firstGap < width && alphaAt(firstGap) !== 0) firstGap += 1;
  if (firstGap <= firstOpaque || firstGap >= width) return fallbackCapRatio;

  const uSpan = Math.max(1e-6, uvDomain.maxU - uvDomain.minU);
  const uAtGap = firstGap / width;
  const ratio = (uAtGap - uvDomain.minU) / uSpan;
  return Math.max(1 / width, Math.min(0.45, ratio));
}

function drawThreeSliceTextureToCanvas(
  ctx: CanvasRenderingContext2D,
  img: HTMLImageElement,
  x: number,
  y: number,
  width: number,
  height: number,
  capPx: number,
) {
  if (width <= 0 || height <= 0) return;

  const srcW = img.width;
  const srcH = img.height;
  const srcCap = Math.min(capPx, Math.floor(srcW / 2));
  const dstCap = Math.min(srcCap, Math.floor(width / 2));

  if (dstCap > 0) {
    ctx.drawImage(img, 0, 0, srcCap, srcH, x, y, dstCap, height);
  }

  const dstCenterW = width - dstCap * 2;
  if (dstCenterW > 0) {
    const srcCenterX = srcCap;
    const srcCenterW = Math.max(1, srcW - srcCap * 2);
    ctx.drawImage(img, srcCenterX, 0, srcCenterW, srcH, x + dstCap, y, dstCenterW, height);
  }

  if (dstCap > 0) {
    ctx.drawImage(img, srcW - srcCap, 0, srcCap, srcH, x + width - dstCap, y, dstCap, height);
  }
}

function drawBuildProgressBarToCanvas(
  canvas: HTMLCanvasElement,
  fillImg: HTMLImageElement,
  borderImg: HTMLImageElement,
  valuePct: number,
  capRatio: number,
) {
  const rect = canvas.getBoundingClientRect();
  const cssW = Math.max(1, rect.width);
  const cssH = Math.max(1, rect.height);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext('2d');
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);
  ctx.imageSmoothingEnabled = true;
  const capPx = Math.max(1, Math.round(cssW * capRatio));

  const fillW = Math.max(0, Math.min(cssW, (valuePct / 100) * cssW));
  if (fillW > 0) {
    drawThreeSliceTextureToCanvas(ctx, fillImg, 0, 0, fillW, cssH, capPx);
  }

  drawThreeSliceTextureToCanvas(ctx, borderImg, 0, 0, cssW, cssH, capPx);
}

function BuildProgressRowBar(props: BuildProgressRowBarProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const renderNonceRef = useRef(0);
  const destroyedRef = useRef(false);

  const renderBar = async () => {
    const canvas = canvasRef.current;
    if (!canvas || destroyedRef.current) return;
    const fillUrl = props.fillUrl;
    const borderUrl = props.borderUrl;
    const currentNonce = ++renderNonceRef.current;

    if (!fillUrl || !borderUrl) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
      }
      return;
    }

    try {
      const [fillImg, borderImg, uvDomain] = await Promise.all([
        loadDataUrlImage(fillUrl),
        loadDataUrlImage(borderUrl),
        loadBuildProgressBarUvDomain(),
      ]);
      if (destroyedRef.current || currentNonce !== renderNonceRef.current) return;
      const capRatio = deriveBuildBarCapRatio(borderImg, uvDomain);
      drawBuildProgressBarToCanvas(canvas, fillImg, borderImg, props.valuePct, capRatio);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    void renderBar();
  }, [props.valuePct, props.fillUrl, props.borderUrl]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const resizeObserver = new ResizeObserver(() => {
      void renderBar();
    });
    resizeObserver.observe(canvas);

    return () => {
      destroyedRef.current = true;
      resizeObserver.disconnect();
    };
  }, []);

  return <canvas ref={canvasRef} className="bundle-chart-bar-canvas" />;
}

export default function BundleSizeSection(props: Props) {
  return (
    <section className="section-card">
      <h3>Leaner than a Blademaster with Wind Walk.</h3>
      <p className="section-desc">
        Tree-shakeable ESM. Import only what you need. Average component weighs under 1.4kb gzipped.
      </p>
      <div className="bundle-chart">
        {components.map((c) => (
          <div key={c.name} className="bundle-chart-row">
            <span className="bundle-chart-label">{c.name}</span>
            <div className="bundle-chart-bar-track">
              <BuildProgressRowBar
                valuePct={(c.size / maxSize) * 100}
                fillUrl={props.buildFillUrl}
                borderUrl={props.buildBorderUrl}
              />
            </div>
            <span className="bundle-chart-size">{c.size}kb</span>
          </div>
        ))}
      </div>
    </section>
  );
}

import { useState, useEffect, useRef } from 'react';

const tokens = [
  { label: 'Background' },
  { label: 'Text' },
  { label: 'Accent' },
  { label: 'Glow' },
] as const;

const factions = [
  { name: 'Human', colors: ['#2a2a3a', '#eceff7', '#4a7abf', '#6db3f2'] },
  { name: 'Orc', colors: ['#2a1f1a', '#f0e0c0', '#bf4a4a', '#ff6644'] },
  { name: 'Night Elf', colors: ['#1a2a2a', '#d0e8e0', '#4abfaa', '#44ffcc'] },
  { name: 'Undead', colors: ['#1a1a2a', '#c8c0d0', '#6a4abf', '#8866ff'] },
] as const;

interface Props {
  borderAtlasUrls: Record<string, string>;
}

interface TokenSwatchProps {
  color: string;
  textColor: string;
  borderAtlasUrl?: string;
}

const editBoxCornerRatio = 0.032 / 0.04;
const editBoxInsetRatio = 0.004 / 0.04;
const imageCache = new Map<string, Promise<HTMLImageElement>>();

function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
  const cached = imageCache.get(url);
  if (cached) return cached;
  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    img.src = url;
  });
  imageCache.set(url, promise);
  return promise;
}

function rotateCellClockwise(atlas: HTMLImageElement, cellIndex: number, cellW: number, cellH: number): HTMLCanvasElement {
  const canvas = document.createElement('canvas');
  canvas.width = cellH;
  canvas.height = cellW;
  const ctx = canvas.getContext('2d');
  if (!ctx) return canvas;
  ctx.translate(cellH, 0);
  ctx.rotate(Math.PI / 2);
  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
  return canvas;
}

function drawHorizontallyTiledEdge(
  ctx: CanvasRenderingContext2D,
  tile: HTMLCanvasElement,
  x: number,
  y: number,
  width: number,
  height: number,
) {
  if (width <= 0 || height <= 0) return;

  let drawn = 0;
  while (drawn < width) {
    const segmentW = Math.min(height, width - drawn);
    const srcW = (segmentW / height) * tile.width;
    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
    drawn += segmentW;
  }
}

function fillRoundedRect(
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  width: number,
  height: number,
  radius: number,
) {
  const r = Math.max(0, Math.min(radius, width * 0.5, height * 0.5));
  if (r <= 0) {
    ctx.fillRect(x, y, width, height);
    return;
  }
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + width - r, y);
  ctx.quadraticCurveTo(x + width, y, x + width, y + r);
  ctx.lineTo(x + width, y + height - r);
  ctx.quadraticCurveTo(x + width, y + height, x + width - r, y + height);
  ctx.lineTo(x + r, y + height);
  ctx.quadraticCurveTo(x, y + height, x, y + height - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
  ctx.fill();
}

function drawEditBoxFrame(canvas: HTMLCanvasElement, borderImg: HTMLImageElement, fillColor: string) {
  const cssW = Math.max(1, canvas.clientWidth || 1);
  const cssH = Math.max(1, canvas.clientHeight || 1);
  const dpr = window.devicePixelRatio || 1;
  const pxW = Math.max(1, Math.round(cssW * dpr));
  const pxH = Math.max(1, Math.round(cssH * dpr));
  if (canvas.width !== pxW || canvas.height !== pxH) {
    canvas.width = pxW;
    canvas.height = pxH;
  }

  const ctx = canvas.getContext('2d');
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, cssW, cssH);
  ctx.imageSmoothingEnabled = true;

  const atlasW = borderImg.width;
  const atlasH = borderImg.height;
  const cellW = atlasW / 8;
  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
  const corner = Math.max(1, Math.floor(Math.min(cssH * editBoxCornerRatio, sourceCornerMax, cssW / 2, cssH / 2)));
  const inset = Math.max(0, Math.floor(Math.min(cssH * editBoxInsetRatio, cssW / 2, cssH / 2)));
  const fillInset = inset + Math.max(1, Math.floor(cssH * 0.02));
  const innerX = fillInset;
  const innerY = fillInset;
  const innerW = Math.max(0, cssW - fillInset * 2);
  const innerH = Math.max(0, cssH - fillInset * 2);
  const innerRadius = Math.max(1, Math.floor(corner * 0.42));

  if (innerW > 0 && innerH > 0) {
    ctx.save();
    ctx.globalAlpha = 0.88;
    ctx.fillStyle = fillColor;
    fillRoundedRect(ctx, innerX, innerY, innerW, innerH, innerRadius);
    ctx.restore();
  }

  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
  };

  drawCell(4, 0, 0, corner, corner);
  drawCell(5, cssW - corner, 0, corner, corner);
  drawCell(6, 0, cssH - corner, corner, corner);
  drawCell(7, cssW - corner, cssH - corner, corner, corner);

  const edgeH = cssH - corner * 2;
  if (edgeH > 0) {
    drawCell(0, 0, corner, corner, edgeH);
    drawCell(1, cssW - corner, corner, corner, edgeH);
  }

  const edgeW = cssW - corner * 2;
  if (edgeW > 0) {
    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
    drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
    drawHorizontallyTiledEdge(ctx, bottomRot, corner, cssH - corner, edgeW, corner);
  }
}

function getHexTextColor(hexColor: string): string {
  const hex = hexColor.replace('#', '');
  const normalized = hex.length === 3
    ? hex.split('').map((ch) => `${ch}${ch}`).join('')
    : hex.padEnd(6, '0').slice(0, 6);
  const r = parseInt(normalized.slice(0, 2), 16);
  const g = parseInt(normalized.slice(2, 4), 16);
  const b = parseInt(normalized.slice(4, 6), 16);
  const luminance = (r * 299 + g * 587 + b * 114) / 1000;
  return luminance > 160 ? '#10151f' : '#f5f8ff';
}

function TokenSwatch(props: TokenSwatchProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const renderNonceRef = useRef(0);
  const destroyedRef = useRef(false);

  const renderSwatch = async () => {
    const canvas = canvasRef.current;
    if (!canvas || destroyedRef.current) return;
    const color = props.color;
    const atlasUrl = props.borderAtlasUrl;
    const currentNonce = ++renderNonceRef.current;

    if (!atlasUrl) {
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      const cssW = Math.max(1, canvas.clientWidth || 1);
      const cssH = Math.max(1, canvas.clientHeight || 1);
      const dpr = window.devicePixelRatio || 1;
      const pxW = Math.max(1, Math.round(cssW * dpr));
      const pxH = Math.max(1, Math.round(cssH * dpr));
      if (canvas.width !== pxW || canvas.height !== pxH) {
        canvas.width = pxW;
        canvas.height = pxH;
      }
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.clearRect(0, 0, cssW, cssH);
      ctx.fillStyle = color;
      ctx.fillRect(0, 0, cssW, cssH);
      return;
    }

    try {
      const borderImg = await loadDataUrlImage(atlasUrl);
      if (destroyedRef.current || currentNonce !== renderNonceRef.current) return;
      drawEditBoxFrame(canvas, borderImg, color);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    void renderSwatch();
  }, [props.color, props.borderAtlasUrl]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const resizeObserver = new ResizeObserver(() => {
      void renderSwatch();
    });
    resizeObserver.observe(canvas);

    return () => {
      destroyedRef.current = true;
      resizeObserver.disconnect();
    };
  }, []);

  return (
    <div className="token-swatch token-swatch--editbox-canvas">
      <canvas ref={canvasRef} className="token-swatch-canvas" />
      <span className="token-hex" style={{ '--token-hex-color': props.textColor } as React.CSSProperties}>{props.color}</span>
    </div>
  );
}

export default function DesignTokensSection(props: Props) {
  return (
    <section className="section-card">
      <h3>Design Tokens</h3>
      <p className="section-desc">
        60+ design tokens per faction. Stone textures, gold gradients, border filigree — all overridable. Your brand guidelines say blue and white? We can work with that. But why would you.
      </p>
      <div className="token-grid">
        <div className="token-grid-header">
          <div />
          {factions.map((f) => (
            <div key={f.name} className="token-faction-label">{f.name}</div>
          ))}
        </div>
        {tokens.map((token, ti) => (
          <div key={token.label} className="token-grid-row">
            <div className="token-name">{token.label}</div>
            {factions.map((f) => {
              const color = f.colors[ti].toUpperCase();
              return (
                <TokenSwatch
                  key={f.name}
                  color={color}
                  textColor={getHexTextColor(color)}
                  borderAtlasUrl={props.borderAtlasUrls[f.name]}
                />
              );
            })}
          </div>
        ))}
      </div>
      <p className="token-caption"><em>"We extracted every pixel from the original UI. Twice."</em></p>
    </section>
  );
}

import { useState, useEffect, useRef } from 'react';
import { decodeBLP, getBLPImageData } from 'war3-model';
import type { Race } from '../../lib/types';
import { RACE_PREFIXES } from '../../state/race';

const previewRaces: Array<{ race: Race; label: string }> = [
